def multi_tensor_model(dataset):
    class MyModel(nn.Module):
        def __init__(self, n):
            super().__init__()
            self.linear = torch.nn.Linear(n, 1)
            self._train = True

        def forward(self, sepal_features, petal_features):
            if not self.training:
                if isinstance(sepal_features, np.ndarray):
                    sepal_features = torch.from_numpy(sepal_features)
                if isinstance(petal_features, np.ndarray):
                    petal_features = torch.from_numpy(petal_features)
                with torch.no_grad():
                    return self.linear(torch.cat((sepal_features, petal_features), dim=-1))
            else:
                return self.linear(torch.cat((sepal_features, petal_features), dim=-1))

    model = MyModel(4)
    model.train()
    dataloader = DataLoader(dataset, batch_size=16, num_workers=1, shuffle=True, drop_last=False)
    criterion = nn.MSELoss()
    optimizer = torch.optim.SGD(model.parameters(), lr=0.01)
    for _ in range(5):
        for batch in dataloader:
            optimizer.zero_grad()
            y_pred = model(*torch.split(batch[0], 2, 1)).squeeze(dim=1)
            loss = criterion(y_pred, batch[1])
            loss.backward()
            optimizer.step()
    model.train(False)
    return model

def translate_span_when_storing(span: Span) -> dict[str, Any]:
    """
    Apply attributes translations to a span's dictionary when storing.

    Supported translations:
    - Token usage attributes from various OTEL schemas
    - Inputs and outputs attributes from various OTEL schemas (including from events)
    - Message format for chat UI rendering

    These attributes translation need to happen when storing spans because we need
    to update TraceInfo accordingly.

    Args:
        span: Span object

    Returns:
        Translated span dictionary
    """
    span_dict = span.to_dict()
    attributes = sanitize_attributes(span_dict.get("attributes", {}))
    events = span_dict.get("events", [])

    # Override UNKNOWN (the LiveSpan default) with the translator-determined type.
    if mlflow_type := translate_span_type_from_otel(attributes):
        current_raw = attributes.get(SpanAttributeKey.SPAN_TYPE)
        current_type = try_json_loads(current_raw) if current_raw else None
        if current_type in (None, SpanType.UNKNOWN):
            attributes[SpanAttributeKey.SPAN_TYPE] = dump_span_attribute_value(mlflow_type)

    # Translate inputs and outputs (check both attributes and events)
    if SpanAttributeKey.INPUTS not in attributes and (
        input_value := _get_input_value(attributes, events)
    ):
        attributes[SpanAttributeKey.INPUTS] = input_value

    if SpanAttributeKey.OUTPUTS not in attributes and (
        output_value := _get_output_value(attributes, events)
    ):
        attributes[SpanAttributeKey.OUTPUTS] = output_value

    # Translate token usage
    if SpanAttributeKey.CHAT_USAGE not in attributes and (
        token_usage := _get_token_usage(attributes)
    ):
        attributes[SpanAttributeKey.CHAT_USAGE] = dump_span_attribute_value(token_usage)

    # Set message format for chat UI rendering
    if SpanAttributeKey.MESSAGE_FORMAT not in attributes and (
        message_format := _get_message_format(attributes)
    ):
        attributes[SpanAttributeKey.MESSAGE_FORMAT] = dump_span_attribute_value(message_format)

    # Translate tool definitions for chat UI rendering
    if SpanAttributeKey.CHAT_TOOLS not in attributes and (
        tools := _get_tool_definitions(attributes)
    ):
        attributes[SpanAttributeKey.CHAT_TOOLS] = tools

    # Extract and normalize model name from various sources
    if SpanAttributeKey.MODEL not in attributes and (model_name := _get_model_name(attributes)):
        attributes[SpanAttributeKey.MODEL] = dump_span_attribute_value(model_name)

    if SpanAttributeKey.MODEL_PROVIDER not in attributes and (
        model_provider := _get_model_provider(attributes)
    ):
        attributes[SpanAttributeKey.MODEL_PROVIDER] = dump_span_attribute_value(model_provider)

    # Calculate cost if both token usage and model are available
    if (
        SpanAttributeKey.LLM_COST not in attributes
        and SpanAttributeKey.CHAT_USAGE in attributes
        and SpanAttributeKey.MODEL in attributes
    ):
        try:
            token_usage = json.loads(attributes[SpanAttributeKey.CHAT_USAGE])
            model_name = json.loads(attributes[SpanAttributeKey.MODEL])
            model_provider = (
                json.loads(attributes[SpanAttributeKey.MODEL_PROVIDER])
                if SpanAttributeKey.MODEL_PROVIDER in attributes
                else None
            )
            if cost := calculate_cost_by_model_and_token_usage(
                model_name, token_usage, model_provider
            ):
                attributes[SpanAttributeKey.LLM_COST] = dump_span_attribute_value(cost)
        except Exception:
            _logger.debug("Failed to calculate cost during OTEL translation", exc_info=True)

    span_dict["attributes"] = attributes
    return span_dict

def _get_model_name(attributes: dict[str, Any]) -> str | None:
    """
    Get model name from span attributes.

    Args:
        attributes: Dictionary of span attributes

    Returns:
        Model name or None if not found
    """
    for translator in _TRANSLATORS:
        if model_name := translator.get_model_name(attributes):
            return model_name

    # Check inputs for model field
    if inputs := attributes.get(SpanAttributeKey.INPUTS):
        try:
            if isinstance(inputs, str):
                inputs = json.loads(inputs)
            if isinstance(inputs, dict) and (model := inputs.get("model")):
                return model if isinstance(model, str) else None
        except Exception:
            _logger.debug("Failed to parse inputs for model name", exc_info=True)

    # Check outputs for model field
    if outputs := attributes.get(SpanAttributeKey.OUTPUTS):
        try:
            if isinstance(outputs, str):
                outputs = json.loads(outputs)
            if isinstance(outputs, dict) and (model := outputs.get("model")):
                return model if isinstance(model, str) else None
        except Exception:
            _logger.debug("Failed to parse outputs for model name", exc_info=True)

    return None

def _run_single_turn_scorer_batch(
    scorer: Any,
    trace_ids: list[str],
    tracking_store: AbstractStore,
    log_assessments: bool,
) -> dict[str, TraceResult]:
    """
    Run a single-turn scorer on each trace in parallel.

    Args:
        scorer: The scorer instance.
        trace_ids: List of trace IDs to evaluate.
        tracking_store: The tracking store instance.
        log_assessments: Whether to log assessments to the traces.

    Returns:
        Dict mapping trace_id to TraceResult.
    """
    trace_map = _fetch_traces_batch(trace_ids, tracking_store)

    def process_trace(trace_id: str, trace: Trace) -> tuple[str, TraceResult]:
        eval_item = EvalItem.from_trace(trace)

        try:
            # Use _compute_eval_scores from harness - supports scorer tracing,
            # captures stack traces on errors
            result = _compute_eval_scores(
                eval_item=eval_item,
                scorers=[scorer],
            )
            feedbacks = result.assessments

            failures = _extract_failures_from_feedbacks(feedbacks)

            if log_assessments and feedbacks:
                _log_assessments(
                    run_id=None,  # No MLflow run context in API path
                    trace=trace,
                    assessments=feedbacks,
                )

            return trace_id, TraceResult(
                assessments=[f.to_dictionary() for f in feedbacks],
                failures=failures,
            )
        except Exception as e:
            return trace_id, TraceResult(
                failures=[ScorerFailure(error_code=type(e).__name__, error_message=str(e))]
            )

    max_workers = min(len(trace_map), MLFLOW_GENAI_EVAL_MAX_WORKERS.get())
    results: dict[str, TraceResult] = {}

    with ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="MlflowScorerInvoke",
    ) as executor:
        futures = {
            executor.submit(process_trace, tid, trace): tid for tid, trace in trace_map.items()
        }
        for future in as_completed(futures):
            trace_id, result = future.result()
            results[trace_id] = result

    return results

def _group_traces_by_session_id(
    trace_ids: list[str],
    tracking_store: AbstractStore,
) -> dict[str, list[str]]:
    """
    Group trace_ids by their session_id metadata.

    Fetches trace info from the tracking store and groups them by session_id.
    Traces without a session_id are skipped.

    Args:
        trace_ids: List of trace IDs to group.
        tracking_store: The tracking store instance.

    Returns:
        Dictionary mapping session_id to list of trace_ids, sorted by timestamp.
    """
    session_groups: dict[str, list[str]] = {}
    # trace_id -> (session_id, timestamp_ms)
    trace_info_cache: dict[str, tuple[str, int | None]] = {}

    trace_infos = tracking_store.batch_get_trace_infos(trace_ids)

    for trace_info in trace_infos:
        trace_metadata = trace_info.trace_metadata or {}
        if session_id := trace_metadata.get(TraceMetadataKey.TRACE_SESSION):
            if session_id not in session_groups:
                session_groups[session_id] = []
            session_groups[session_id].append(trace_info.trace_id)
            trace_info_cache[trace_info.trace_id] = (session_id, trace_info.timestamp_ms)

    # Sort trace_ids within each session by trace timestamp (None timestamps sort last)
    for session_id in session_groups:
        session_groups[session_id] = sorted(
            session_groups[session_id],
            key=lambda tid: trace_info_cache.get(tid, ("", None))[1] or float("inf"),
        )

    return session_groups

def _message(self) -> str:
        return (
            "Use `next(x for x in items if condition)` instead of "
            "`[x for x in items if condition][0]` for finding the first matching element."
        )

def main(data_dir, temperature, top_p, api_addr, api_key, api_port, multiworker, llm, use_demos, reformat, reformat_by, tag, dependency_type, log_first_detail):
    assert dependency_type in ["resource", "temporal"], "Dependency type not supported"
    if dependency_type == "resource":
        assert data_dir != "data_dailylifeapis", "Resource dependency type only support data_huggingface and data_multimedia"

    arguments = locals()
    url = f"http://{api_addr}:{api_port}/v1/chat/completions"
    header = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }

    prediction_dir = f"{data_dir}/predictions{f'_use_demos_{use_demos}' if use_demos and tag else ''}{f'_reformat_by_{ reformat_by}' if reformat and tag else ''}"
    wf_name = f"{prediction_dir}/{llm}.json"

    if not os.path.exists(prediction_dir):
        os.makedirs(prediction_dir, exist_ok=True)

    has_inferenced = []
    if os.path.exists(wf_name):
        rf = open(wf_name, "r")
        for line in rf:
            data = json.loads(line)
            has_inferenced.append(data["id"])
        rf.close()

    rf_ur = open(f"{data_dir}/user_requests.json", "r")
    inputs = []
    for line in rf_ur:
        input = json.loads(line)
        if input["id"] not in has_inferenced:
            inputs.append(input)
    rf_ur.close()

    wf = open(wf_name, "a")

    tool_list = json.load(open(f"{data_dir}/tool_desc.json", "r"))["nodes"]
    if "input-type" not in tool_list[0]:
        assert dependency_type == "temporal", "Tool type is not ignored, but the tool list does not contain input-type and output-type"
    if dependency_type == "temporal":
        for tool in tool_list:
            parameter_list = []
            for parameter in tool["parameters"]:
                parameter_list.append(parameter["name"])
            tool["parameters"] = parameter_list

    # log llm name in format
    formatter = logging.Formatter(f"%(asctime)s - [ {llm} ] - %(levelname)s - %(message)s")
    console_handler = logging.StreamHandler()
    console_handler.setFormatter(formatter)
    console_handler.setLevel(logging.INFO)
    logger.addHandler(console_handler)

    file_handler = logging.FileHandler(f"{prediction_dir}/{llm}.log")
    file_handler.setFormatter(formatter)
    file_handler.setLevel(logging.INFO)
    logger.addHandler(file_handler)

    # logging all args
    logger.info(f"Arguments: {arguments}")

    demos = []
    if use_demos:
        if dependency_type == "temporal":
            demos_id = [ "38563456", "27267145", "91005535"]
        else:
            if "huggingface" in data_dir: 
                demos_id = [ "10523150", "14611002", "22067492"]
            elif "multimedia" in data_dir:
                demos_id = [ "30934207", "20566230", "19003517"]
        demos_id = demos_id[:use_demos]
        logger.info(f"Use {len(demos_id)} demos: {demos_id}")
        demos_rf = open(f"{data_dir}/data.json", "r")
        for line in demos_rf:
            data = json.loads(line)
            if data["id"] in demos_id:
                if dependency_type == "temporal":
                    demo = {
                        "user_request": data["user_request"],
                        "result":{
                            "task_steps": data["task_steps"],
                            "task_nodes": data["task_nodes"],
                            "task_links": data["task_links"]
                        }
                    }
                else:
                    demo = {
                        "user_request": data["user_request"],
                        "result":{
                            "task_steps": data["task_steps"],
                            "task_nodes": data["task_nodes"]
                        }
                    }
                demos.append(demo)
        demos_rf.close()

    tool_string = "# TASK LIST #:\n"
    for k, tool in enumerate(tool_list):
        tool_string += json.dumps(tool) + "\n"

    sem = asyncio.Semaphore(multiworker)

    async def inference_wrapper(input, url, header, temperature, top_p, tool_string, wf, llm, demos, reformat, reformat_by, dependency_type, log_detail = False):
        async with sem:
            await inference(input, url, header, temperature, top_p, tool_string, wf, llm, demos, reformat, reformat_by, dependency_type, log_detail)

    if len(inputs) == 0:
        logger.info("All Completed!")
        return
    else:
        logger.info(f"Detected {len(has_inferenced)} has been inferenced,")
        logger.info(f"Start inferencing {len(inputs)} tasks...")

    loop = asyncio.get_event_loop()

    if log_first_detail:
        tasks = [inference_wrapper(inputs[0], url, header, temperature, top_p, tool_string, wf, llm, demos, reformat, reformat_by, dependency_type, log_detail=True)]
        results = loop.run_until_complete(asyncio.gather(*tasks, return_exceptions=True))
        inputs = inputs[1:]

    tasks = []
    for input in inputs:
        tasks.append(inference_wrapper(input, url, header, temperature, top_p, tool_string, wf, llm, demos, reformat, reformat_by, dependency_type))

    results += loop.run_until_complete(asyncio.gather(*tasks, return_exceptions=True))
    failed = []
    done = []
    for result in results:
        if isinstance(result, Exception):
            failed.append(result)
        else:
            done.append(result)
    logger.info(f"Completed: {len(done)}")
    logger.info(f"Failed: {len(failed)}")
    loop.close()

async def get_response(url, header, payload, id, reformat, reformat_by, dependency_type, log_detail=False):
    async with aiohttp.ClientSession() as session:
        async with session.post(url, headers=header, data=payload, timeout=300) as response:
            resp = await response.json()

    if response.status == 429:
        raise RateLimitError(f"{resp}")
    if response.status != 200:
        raise Exception(f"{resp}")

    if log_detail:
        logger.info(json.loads(payload)["messages"][0]["content"])
        logger.info(resp["choices"][0]["message"]["content"])

    oring_content = resp["choices"][0]["message"]["content"]
    oring_content = oring_content.replace("\n", "")
    oring_content = oring_content.replace("\_", "_")
    content = oring_content.replace("\\", "")

    start_pos = content.find("RESULT #:")
    if start_pos!=-1:
        content = content[start_pos+len("RESULT #:"):]

    content = content[content.find("{"):content.rfind("}")+1]
    try:
        content = json.loads(content)
        if isinstance(content, list) and len(content):
            merge_content = {}
            for c in content:
                for k, v in c.items():
                    merge_content[k].extend(v) if k in merge_content else merge_content.update({k: v})
        return content
    except json.JSONDecodeError as e:
        if reformat:
            if dependency_type == "resource":
                prompt = """Please format the result # RESULT # to a strict JSON format # STRICT JSON FORMAT #. \nRequirements:\n1. Do not change the meaning of task steps and task nodes;\n2. Don't tolerate any possible irregular formatting to ensure that the generated content can be converted by json.loads();\n3. You must output the result in this schema: {"task_steps": [ step description of one or more steps ], "task_nodes": [{"task": "tool name must be from # TOOL LIST #", "arguments": [ a concise list of arguments for the tool. Either original text, or user-mentioned filename, or tag '<node-j>' (start from 0) to refer to the output of the j-th node. ]}]}\n# RESULT #:{{illegal_result}}\n# STRICT JSON FORMAT #:"""
            else:
                prompt = """Please format the result # RESULT # to a strict JSON format # STRICT JSON FORMAT #. \nRequirements:\n1. Do not change the meaning of task steps, task nodes and task links;\n2. Don't tolerate any possible irregular formatting to ensure that the generated content can be converted by json.loads();\n3. Pay attention to the matching of brackets. Write in a compact format and avoid using too many space formatting controls;\n4. You must output the result in this schema: {"task_steps": [ "concrete steps, format as Step x: Call xxx tool with xxx: 'xxx' and xxx: 'xxx'" ], "task_nodes": [{"task": "task name must be from # TASK LIST #", "arguments": [ {"name": "parameter name", "value": "parameter value, either user-specified text or the specific name of the tool whose result is required by this node"} ]}], "task_links": [{"source": "task name i", "target": "task name j"}]}\n# RESULT #:{{illegal_result}}\n# STRICT JSON FORMAT #:"""
            prompt = prompt.replace("{{illegal_result}}", oring_content)
            payload = json.loads(payload)
            if reformat_by != "self":
                payload["model"] = reformat_by

            if log_detail:
                logger.info(f"{emoji.emojize(':warning:')}  #id {id} Illegal JSON format: {content}")
                logger.info(f"{emoji.emojize(':sparkles:')} #id {id} Detected illegal JSON format, try to reformat by {payload['model']}...")

            payload["messages"][0]["content"] = prompt
            payload = json.dumps(payload)

            async with aiohttp.ClientSession() as session:
                async with session.post(url, headers=header, data=payload, timeout=120) as response:
                    resp = await response.json()

            if response.status == 429:
                raise RateLimitError(f"{resp}")
            if response.status != 200:
                raise Exception(f"{resp}")

            if log_detail:
                logger.info(json.loads(payload)["messages"][0]["content"])
                logger.info(resp["choices"][0]["message"]["content"])

            content = resp["choices"][0]["message"]["content"]
            content = content.replace("\n", "")
            content = content.replace("\_", "_")
            start_pos = content.find("STRICT JSON FORMAT #:")
            if start_pos!=-1:
                content = content[start_pos+len("STRICT JSON FORMAT #:"):]

            content = content[content.find("{"):content.rfind("}")+1]
            try:
                content = json.loads(content)
                return content
            except json.JSONDecodeError as e:
                raise ContentFormatError(f"{content}")
        else:
            raise ContentFormatError(f"{content}")

def main(temperature, top_p, check, graph_desc, tool_desc, api_addr, api_port, api_key, play, method, tool_number, number_of_samples, seed, data_dir, save_figure, multiworker, llm, use_async, dependency_type):
    args = locals()
    url = f"http://{api_addr}:{api_port}/v1/chat/completions"
    header = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }
    now = datetime.now()

    if data_dir:
        if os.path.exists(data_dir):
            if graph_desc or tool_desc:
                warnings.warn(f"Data directory {data_dir} already exists, tool graph and tool desc will be ignored.")
            graph_desc = f"{data_dir}/graph_desc.json"
            tool_desc = f"{data_dir}/tool_desc.json"
    else:
        data_dir = f"result_{now.strftime('%Y%m%d%H%M%S')}_{llm}_t{temperature}_p{top_p}{'_check' if check else ''}".replace(".", "_")

    assert data_dir and graph_desc and tool_desc

    if seed > -1:
        random.seed(seed)

    tool_list = json.load(open(tool_desc, "r"))["nodes"]
    tools = {}
    if dependency_type == "resource":
        assert "input-type" in tool_list[0] and "output-type" in tool_list[0], "Input and output types are not defined"
        for tool in tool_list:
            tools[tool["id"]] = {"id": tool["id"], "desc": tool["desc"], "input-type": tool["input-type"], "output-type": tool["output-type"]}
    elif dependency_type == "temporal":
        assert "parameters" in tool_list[0], "Parameters are not defined"
        for tool in tool_list:
            tools[tool["id"]] = {"id": tool["id"], "desc": tool["desc"], "parameters": tool["parameters"]}
    else:
        raise ValueError(f"Unsupported dependency type: {dependency_type}")

    sampler = GraphSampler(file_name=graph_desc)

    if play:
        assert method is not None
        assert tool_number is not None
        result = asyncio.run(sample(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, "./", None, dependency_type))
        logger.info(json.dumps(result, indent=2))
        return

    figure_dir = None

    if not os.path.exists(data_dir):
        os.makedirs(data_dir, exist_ok=True)
        shutil.copy(graph_desc, f"{data_dir}/graph_desc.json")
        shutil.copy(tool_desc, f"{data_dir}/tool_desc.json")

    output = f"{data_dir}/data_raw.json"
    statistics_output = f"{data_dir}/statistics.json"

    file_handler = logging.FileHandler(f"{data_dir}/data_engine.log")
    file_handler.setFormatter(logging.Formatter("%(asctime)s - %(name)s - %(levelname)s - %(message)s"))
    file_handler.setLevel(logging.INFO)
    logger.addHandler(file_handler)

    logger.info(json.dumps(args))

    if save_figure:
        figure_dir = f"{data_dir}/task_graphs"
        os.makedirs(figure_dir, exist_ok=True)

    wf = open(output, "a")
    statistics_wf = open(f"{statistics_output}", "a")
    args["start_time"] = now.strftime("%Y-%m-%d %H:%M:%S")
    statistics_wf.write(json.dumps(args) + "\n")

    method_weights = {
        "single": 3,
        "chain": 7,
        "dag": 8,
    }

    number_weights = {
        2: 0.1,
        3: 0.2,
        4: 0.3,
        5: 0.2,
        6: 0.1,
        7: 0.05,
        8: 0.025,
        9: 0.025,
        10: 0.025,
    }

    statistics = {"total": 0, "avg_time_per_sample": 0, "success": 0, "fail": 0}
    done, failed = [], []
    if use_async:
        # coroutine with Semaphore
        sem = asyncio.Semaphore(multiworker)
        async def sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type):
            async with sem:  # semaphore limits num of simultaneous sampling
                if statistics["total"] % 100 == 0 and statistics["total"] != 0:
                    logger.info(json.dumps(statistics, indent=2))
                    statistics_wf.write(json.dumps(statistics) + "\n")
                try:
                    await sample(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, dependency_type)
                except Exception as e:
                    statistics["total"] += 1
                    statistics["fail"] += 1
                    if str(type(e)) not in statistics:
                        statistics[str(type(e))] = 0
                    statistics[str(type(e))] += 1
                    raise e
                statistics["total"] += 1
                statistics["success"] += 1
                statistics["avg_time_per_sample"] = str((datetime.now() - now) / statistics["success"])

        async def run(url, header, llm, temperature, top_p, check, sampler, tools, figure_dir, wf, statistics, now, dependency_type):
            method = random.choices(list(method_weights.keys()), weights=list(method_weights.values()))[0]
            if method == "single":
                tool_number = 1
            else:
                tool_number = random.choices(list(number_weights.keys()), weights=list(number_weights.values()))[0]
                if method == "dag":
                    tool_number = max(tool_number, 3)
            await sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type)

        tasks = []
        for _ in range(number_of_samples):
            tasks.append(run(url, header, llm, temperature, top_p, check, sampler, tools, figure_dir, wf, statistics, now, dependency_type))

        loop = asyncio.get_event_loop()
        results = loop.run_until_complete(asyncio.gather(*tasks, return_exceptions=True))

        for result in results:
            if isinstance(result, Exception):
                failed.append(result)
            else:
                done.append(result)
    else:
        # multi-thread with ThreadPoolExecutor
        executor = ThreadPoolExecutor(max_workers=multiworker)
        def sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type):
            if statistics["total"] % 100 == 0 and statistics["total"] != 0:
                logger.info(json.dumps(statistics, indent=2))
                statistics_wf.write(json.dumps(statistics) + "\n")
            try:
                asyncio.run(sample(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, dependency_type))
            except Exception as e:
                statistics["total"] += 1
                statistics["fail"] += 1
                if str(type(e)) not in statistics:
                    statistics[str(type(e))] = 0
                statistics[str(type(e))] += 1
                raise e
            statistics["total"] += 1
            statistics["success"] += 1
            statistics["avg_time_per_sample"] = str((datetime.now() - now) / statistics["success"])

        def run(url, header, llm, temperature, top_p, check, sampler, tools, figure_dir, wf, statistics, now, dependency_type):
            method = random.choices(list(method_weights.keys()), weights=list(method_weights.values()))[0]
            if method == "single":
                tool_number = 1
            else:
                tool_number = random.choices(list(number_weights.keys()), weights=list(number_weights.values()))[0]
                if method == "dag":
                    tool_number = max(tool_number, 3)
            sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type)

        tasks = []
        for _ in range(number_of_samples):
            tasks.append(executor.submit(run, url, header, llm, temperature, top_p, check, sampler, tools, figure_dir, wf, statistics, now, dependency_type))
        for future in as_completed(tasks):
            try:
                future.result()
                done.append(future)
            except Exception as e:
                failed.append(future)

    statistics_wf.write(json.dumps(statistics) + "\n")
    logger.info(f"Done: {len(done)}, Failed: {len(failed)}")

async def run(url, header, llm, temperature, top_p, check, sampler, tools, figure_dir, wf, statistics, now, dependency_type):
            method = random.choices(list(method_weights.keys()), weights=list(method_weights.values()))[0]
            if method == "single":
                tool_number = 1
            else:
                tool_number = random.choices(list(number_weights.keys()), weights=list(number_weights.values()))[0]
                if method == "dag":
                    tool_number = max(tool_number, 3)
            await sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type)

def sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type):
            if statistics["total"] % 100 == 0 and statistics["total"] != 0:
                logger.info(json.dumps(statistics, indent=2))
                statistics_wf.write(json.dumps(statistics) + "\n")
            try:
                asyncio.run(sample(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, dependency_type))
            except Exception as e:
                statistics["total"] += 1
                statistics["fail"] += 1
                if str(type(e)) not in statistics:
                    statistics[str(type(e))] = 0
                statistics[str(type(e))] += 1
                raise e
            statistics["total"] += 1
            statistics["success"] += 1
            statistics["avg_time_per_sample"] = str((datetime.now() - now) / statistics["success"])

def run(url, header, llm, temperature, top_p, check, sampler, tools, figure_dir, wf, statistics, now, dependency_type):
            method = random.choices(list(method_weights.keys()), weights=list(method_weights.values()))[0]
            if method == "single":
                tool_number = 1
            else:
                tool_number = random.choices(list(number_weights.keys()), weights=list(number_weights.values()))[0]
                if method == "dag":
                    tool_number = max(tool_number, 3)
            sample_with_statistics(url, header, llm, temperature, top_p, check, tool_number, sampler, tools, method, figure_dir, wf, statistics, now, dependency_type)

def log_message(self, format, *args):
        """Suppress default logging."""
        pass

def do_GET(self):
        """Handle GET requests."""
        parsed_path = urlparse(self.path)
        path = parsed_path.path
        query_params = parse_qs(parsed_path.query)

        # Route requests
        if path == "/":
            self._serve_home()
        elif path == "/products":
            self._serve_products()
        elif path == "/projects":
            self._serve_projects()
        elif path == "/api/data.json":
            self._serve_json_data()
        elif path == "/api/data.xml":
            self._serve_xml_data()
        elif path == "/api/data.csv":
            self._serve_csv_data()
        elif path == "/slow":
            self._serve_slow_response()
        elif path == "/error/404":
            self._serve_404()
        elif path == "/error/500":
            self._serve_500()
        elif path == "/rate-limited":
            self._serve_rate_limited()
        elif path == "/dynamic":
            self._serve_dynamic_content()
        elif path == "/pagination":
            self._serve_pagination(query_params)
        else:
            self._serve_404()

def stop(self):
        """Stop the mock server."""
        if self.server:
            self.server.shutdown()
            self.server.server_close()
        if self.thread:
            self.thread.join(timeout=1)

def get_url(self, path: str = "") -> str:
        """Get full URL for a given path."""
        return f"http://{self.host}:{self.port}{path}"

def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit."""
        self.stop()

def syntax_focused_code_generation(
    state: Dict[str, Any], analysis: str, llm_model
) -> str:
    """
    Generates corrected code based on syntax error analysis.

    Args:
        state (dict): Contains the 'generated_code'.
        analysis (str): The analysis of the syntax errors.
        llm_model: The language model used for generating the corrected code.

    Returns:
        str: The corrected code.

    Raises:
        InvalidCorrectionStateError: If state is missing required keys.

    Example:
        >>> state = {
            'generated_code': 'print("Hello World"'
        }
        >>> analysis = "Missing closing parenthesis in print statement"
        >>> corrected_code = syntax_focused_code_generation(state, analysis, mock_llm)
    """
    try:
        # Validate state using Pydantic model
        validated_state = CorrectionState(
            generated_code=state.get("generated_code", "")
        )

        if not analysis or not isinstance(analysis, str):
            raise InvalidCorrectionStateError("Analysis must be a non-empty string")

        # Create prompt template and chain
        prompt = PromptTemplate(
            template=get_optimal_correction_template("syntax"),
            input_variables=["analysis", "generated_code"],
        )
        chain = prompt | llm_model | StrOutputParser()

        # Execute chain with validated state
        return chain.invoke(
            {"analysis": analysis, "generated_code": validated_state.generated_code}
        )

    except KeyError as e:
        raise InvalidCorrectionStateError(
            f"Missing required key in state dictionary: {e}"
        )
    except Exception as e:
        raise CodeGenerationError(f"Syntax code generation failed: {str(e)}")

